import{_ as t,o as a,c as s,ag as r}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"Flaky tests & analytics","description":"","frontmatter":{"title":"Flaky tests & analytics","lang":"en-US"},"headers":[],"relativePath":"flaky-tests.md","filePath":"flaky-tests.md","lastUpdated":1782490880000}'),o={name:"flaky-tests.md"};function i(n,e,l,d,c,h){return a(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="flaky-tests-analytics" tabindex="-1">Flaky tests &amp; analytics <a class="header-anchor" href="#flaky-tests-analytics" aria-label="Permalink to &quot;Flaky tests &amp; analytics&quot;">​</a></h1><p>Once Piwi has a few runs of history, it turns them into cross-run intelligence: which tests are flaky, what&#39;s regressing, where time is wasted, and how performance trends over time. This page covers the analytics features beyond a single run.</p><h2 id="flaky-test-detection" tabindex="-1">Flaky test detection <a class="header-anchor" href="#flaky-test-detection" aria-label="Permalink to &quot;Flaky test detection&quot;">​</a></h2><p>A test is flaky when its result isn&#39;t deterministic. Piwi computes a <strong>composite flakiness score</strong> per test from three signals:</p><ul><li><strong>Retry passes</strong> — failed on the first attempt, passed on retry.</li><li><strong>Status alternation</strong> — flips between pass and fail across runs.</li><li><strong>Failure rate</strong> — overall proportion of failures.</li></ul><p>Each project has a dedicated <strong>Flaky tests</strong> tab with a <strong>configurable lookback window</strong> so you can focus on recent behavior or a longer baseline.</p><h3 id="root-cause-classification" tabindex="-1">Root-cause classification <a class="header-anchor" href="#root-cause-classification" aria-label="Permalink to &quot;Root-cause classification&quot;">​</a></h3><p>Every flaky test is automatically tagged with one of five categories, using keyword and distribution heuristics over its errors, steps, and browser spread:</p><table tabindex="0"><thead><tr><th>Category</th><th>Typical signals</th></tr></thead><tbody><tr><td><code>timing</code></td><td>Timeouts, &quot;to be visible&quot;, <code>waitFor</code>, element-not-found-within</td></tr><tr><td><code>network</code></td><td><code>net::</code> / <code>ERR_</code> errors, 5xx responses, <code>ECONNREFUSED</code>, <code>waitForResponse</code></td></tr><tr><td><code>assertion</code></td><td><code>expect(...)</code>, &quot;Expected:&quot;, snapshot/screenshot comparison — with no timing/network noise</td></tr><tr><td><code>environment</code></td><td>Fails repeatedly on exactly one browser while others pass</td></tr><tr><td><code>other</code></td><td>No clear signal</td></tr></tbody></table><p>Filter the flaky table by category to triage a class of failures at once.</p><h3 id="impact-ranking" tabindex="-1">Impact ranking <a class="header-anchor" href="#impact-ranking" aria-label="Permalink to &quot;Impact ranking&quot;">​</a></h3><p>Not all flaky tests are equally expensive. Piwi ranks them by <strong>impact</strong> — derived from wasted CI minutes (retries × average failed duration) and pipeline-block effect — so you fix the ones that hurt most first. A color-coded dot makes it scannable:</p><ul><li>🟢 green — under 5 wasted minutes</li><li>🟡 amber — under 30 minutes</li><li>🔴 red — 30 minutes or more</li></ul><h3 id="per-test-stability-trend" tabindex="-1">Per-test stability trend <a class="header-anchor" href="#per-test-stability-trend" aria-label="Permalink to &quot;Per-test stability trend&quot;">​</a></h3><p>Each test case has a <strong>stability trend</strong>: a time series of pass rate, flaky rate, and average duration, bucketed over time — so you can see whether a fix actually stuck.</p><h2 id="run-insights" tabindex="-1">Run insights <a class="header-anchor" href="#run-insights" aria-label="Permalink to &quot;Run insights&quot;">​</a></h2><p>The <strong>Insights</strong> tab on a run compares it against its last passing baseline and surfaces what changed:</p><ul><li><strong>New regressions</strong> — tests that newly started failing</li><li><strong>Recurring failures</strong> — failing again</li><li><strong>Fixed</strong> — previously failing, now passing</li><li><strong>New flaky</strong> — newly flaky tests</li><li><strong>Performance changes</strong> — most regressed / most improved</li><li><strong>Worker imbalance</strong> — uneven load across workers</li><li><strong>New failure clusters</strong></li></ul><h2 id="regression-signals" tabindex="-1">Regression signals <a class="header-anchor" href="#regression-signals" aria-label="Permalink to &quot;Regression signals&quot;">​</a></h2><p>Individual test cases in a run carry at-a-glance badges:</p><ul><li><strong><code>NEW</code></strong> (red) — a new regression</li><li><strong><code>FLAKY</code></strong> (purple) — newly flaky</li></ul><p>Toggle filters on the run&#39;s test-case list to show only new regressions or new flaky tests.</p><h2 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h2><ul><li><strong>Duration trends</strong> — average and <strong>P90</strong> over time, so a few slow outliers don&#39;t hide a real regression.</li><li><strong>Slowest tests</strong> — the top offenders ranked by duration.</li><li><strong>Run comparison</strong> — a side-by-side delta of two runs with improved / regressed / unchanged summaries.</li><li><strong>Network analysis</strong> — slow API calls grouped by method and normalized route (e.g. <code>/api/users/:id</code>).</li><li><strong>Browser Web Vitals</strong> — TTFB, DOMContentLoaded, FCP and more, with color-coded thresholds.</li></ul><h2 id="spec-health-heatmap" tabindex="-1">Spec health heatmap <a class="header-anchor" href="#spec-health-heatmap" aria-label="Permalink to &quot;Spec health heatmap&quot;">​</a></h2><p>A project-level overview groups test cases by spec file and colors each by pass rate, so an unhealthy area of the suite jumps out. Cells link straight to the filtered test-case list.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./ui-overview.html">UI overview</a> — where each of these views lives in the dashboard</li><li><a href="./reporter.html">Reporter</a> — how retries, traces, network, and Web Vitals get captured</li><li><a href="./ai-diagnosis.html">AI diagnosis &amp; failure clustering</a> — explain the failures behind the trends</li></ul>',28)])])}const p=t(o,[["render",i]]);export{u as __pageData,p as default};
